#!/usr/bin/env bash
# Copyright IBM Corp. 2024, 2026
# SPDX-License-Identifier: BUSL-1.1
#
# Cuts a consul (community edition) point release branch, prepares it, and opens a
# release-preparation PR.
#
# Workflow:
#   1. Create   <CONSUL_RELEASE_BRANCH>       (e.g. release/1.22.9) from a long-lived
#              source branch                 (e.g. release/1.22.x)
#   2. Create   prepare-release-<version>    from <CONSUL_RELEASE_BRANCH>
#   3. Bump version/VERSION and prepend the CHANGELOG.md entry generated by the
#              hashicorp/go-changelog `changelog-build` tool from .changelog/
#   4. Open a PR: prepare-release-<version> -> <CONSUL_RELEASE_BRANCH> and print its URL
#
# Usage:
#   export CONSUL_RELEASE_VERSION=1.22.9        # version being released
#   export CONSUL_PREVIOUS_VERSION=1.22.8       # previous release (changelog range)
#   export CONSUL_RELEASE_BRANCH=release/1.22.9 # point release branch (PR base)
#   export CONSUL_SOURCE_BRANCH=release/1.22.x  # long-lived branch to cut from
#   ./release-scripts/prepare-release-branch.sh [options]
#
# Options:
#   -n, --dry-run   Print the commands that would run; create/change/push nothing.
#   -y, --yes       Non-interactive: skip the prompts and confirmation, use env values.
#   -h, --help      Show this help and exit.
#
# Without -y, the script prompts for every setting below, showing the current env
# value (or a derived default) that you can accept (press Enter) or override:
#   CONSUL_RELEASE_VERSION, CONSUL_PREVIOUS_VERSION, CONSUL_RELEASE_BRANCH,
#   CONSUL_SOURCE_BRANCH, CONSUL_RELEASE_DATE, REMOTE
#
# Derived defaults (used when the corresponding env var is unset):
#   CONSUL_RELEASE_BRANCH = release/<CONSUL_RELEASE_VERSION>
#   CONSUL_SOURCE_BRANCH  = release/<major>.<minor>.x
#   CONSUL_RELEASE_DATE   = today (e.g. "July 1, 2026")
#   REMOTE                = origin
#
# The CHANGELOG entry uses a plain header (e.g. "## 1.22.9 (July 1, 2026)") and the
# changelog range is taken from the previous release tag (e.g. v1.22.8).

set -euo pipefail

usage() {
  sed -n '/^# Cuts /,/^set /p' "$0" | sed '/^set /d; s/^# \{0,1\}//; s/^#$//'
}

# -----------------------------------------------------------------------------
# Flags
# -----------------------------------------------------------------------------
DRY_RUN=false
INTERACTIVE=true
while [[ $# -gt 0 ]]; do
  case "$1" in
    -n | --dry-run) DRY_RUN=true ;;
    -y | --yes) INTERACTIVE=false ;;
    -h | --help)
      usage
      exit 0
      ;;
    *)
      echo "Unknown argument: $1" >&2
      usage >&2
      exit 1
      ;;
  esac
  shift
done

# run CMD...  Runs CMD, or in dry-run mode prints it (shell-quoted) instead.
run() {
  if [[ "${DRY_RUN}" == "true" ]]; then
    { printf '  [dry-run] $'; printf ' %q' "$@"; printf '\n'; }
  else
    "$@"
  fi
}

# fail_or_warn MESSAGE  Errors out normally; in dry-run only warns so the preview
# can run to completion.
fail_or_warn() {
  if [[ "${DRY_RUN}" == "true" ]]; then
    echo "Warning (dry-run): $1" >&2
  else
    echo "Error: $1" >&2
    exit 1
  fi
}

# prompt_var VAR_NAME DEFAULT_VALUE [required]
# Shows the value that will be used and lets the user accept or override it.
prompt_var() {
  local var_name="$1"
  local default_value="$2"
  local required="${3:-}"
  local input
  while :; do
    read -r -p "  ${var_name} [${default_value}]: " input || true
    input="${input:-${default_value}}"
    if [[ -z "${input}" && "${required}" == "required" ]]; then
      echo "  ${var_name} is required; please enter a value." >&2
      continue
    fi
    break
  done
  printf -v "${var_name}" '%s' "${input}"
}

REMOTE="${REMOTE:-origin}"

# -----------------------------------------------------------------------------
# Prerequisite checks (git is always required; the rest only warn in dry-run)
# -----------------------------------------------------------------------------
for cmd in git gh go; do
  if ! command -v "${cmd}" >/dev/null 2>&1; then
    if [[ "${cmd}" == "git" ]]; then
      echo "Error: required command 'git' not found in PATH." >&2
      exit 1
    fi
    fail_or_warn "required command '${cmd}' not found in PATH."
  fi
done

if ! gh auth status >/dev/null 2>&1; then
  fail_or_warn "GitHub CLI is not authenticated. Run 'gh auth login' and try again."
fi

# -----------------------------------------------------------------------------
# Collect / confirm settings (prompt for each, seeded from env or a default)
# -----------------------------------------------------------------------------
if [[ "${INTERACTIVE}" == "true" ]]; then
  echo "Confirm release settings (press Enter to keep the shown value, or type a new one):"
  echo
fi

# CONSUL_RELEASE_VERSION comes first because the other defaults derive from it.
CONSUL_RELEASE_VERSION="${CONSUL_RELEASE_VERSION:-}"
if [[ "${INTERACTIVE}" == "true" ]]; then
  prompt_var CONSUL_RELEASE_VERSION "${CONSUL_RELEASE_VERSION}" required
fi
: "${CONSUL_RELEASE_VERSION:?CONSUL_RELEASE_VERSION is required (set it or run interactively)}"
# Normalize: strip any leading "v" so we compose versions and tags consistently.
CONSUL_RELEASE_VERSION="${CONSUL_RELEASE_VERSION#v}"

# Derive defaults from the (possibly just-entered) version.
_major="${CONSUL_RELEASE_VERSION%%.*}"
_rest="${CONSUL_RELEASE_VERSION#*.}"
_minor="${_rest%%.*}"
CONSUL_RELEASE_BRANCH="${CONSUL_RELEASE_BRANCH:-release/${CONSUL_RELEASE_VERSION}}"
CONSUL_SOURCE_BRANCH="${CONSUL_SOURCE_BRANCH:-release/${_major}.${_minor}.x}"
CONSUL_RELEASE_DATE="${CONSUL_RELEASE_DATE:-$(date "+%B %-d, %Y")}"
CONSUL_PREVIOUS_VERSION="${CONSUL_PREVIOUS_VERSION:-}"

if [[ "${INTERACTIVE}" == "true" ]]; then
  prompt_var CONSUL_PREVIOUS_VERSION "${CONSUL_PREVIOUS_VERSION}" required
  prompt_var CONSUL_RELEASE_BRANCH   "${CONSUL_RELEASE_BRANCH}"   required
  prompt_var CONSUL_SOURCE_BRANCH    "${CONSUL_SOURCE_BRANCH}"    required
  prompt_var CONSUL_RELEASE_DATE     "${CONSUL_RELEASE_DATE}"     required
  prompt_var REMOTE                  "${REMOTE}"                  required
  echo
fi
: "${CONSUL_PREVIOUS_VERSION:?CONSUL_PREVIOUS_VERSION is required (set it or run interactively)}"
# Normalize the previous version the same way before composing the previous release tag.
CONSUL_PREVIOUS_VERSION="${CONSUL_PREVIOUS_VERSION#v}"

# The CHANGELOG header and previous release tag both use a plain (non-"+ent") form.
CHANGELOG_HEADER="## ${CONSUL_RELEASE_VERSION} (${CONSUL_RELEASE_DATE})"
PREVIOUS_RELEASE_TAG="v${CONSUL_PREVIOUS_VERSION}"

export CONSUL_RELEASE_VERSION CONSUL_PREVIOUS_VERSION CONSUL_RELEASE_BRANCH \
  CONSUL_SOURCE_BRANCH CONSUL_RELEASE_DATE REMOTE

PREPARE_BRANCH="prepare-release-${CONSUL_RELEASE_VERSION}"

# Operate from the repository root so file paths and git run against the right tree.
REPO_ROOT="$(git rev-parse --show-toplevel)"
cd "${REPO_ROOT}"

# A dirty tree would be carried onto the new branches, so require a clean start.
if [[ -n "$(git status --porcelain)" ]]; then
  fail_or_warn "working tree is not clean. Commit or stash your changes first."
fi

# -----------------------------------------------------------------------------
# Show the plan (and confirm before any push / PR, which are not reversible)
# -----------------------------------------------------------------------------
cat <<EOF
The following actions will be performed on remote '${REMOTE}':

  Source branch (long-lived)           = ${CONSUL_SOURCE_BRANCH}
  Release branch (created/used)        = ${CONSUL_RELEASE_BRANCH}
  Prepare branch (new)                 = ${PREPARE_BRANCH}

  CONSUL_RELEASE_VERSION               = ${CONSUL_RELEASE_VERSION}
  CONSUL_PREVIOUS_VERSION              = ${CONSUL_PREVIOUS_VERSION}
  CHANGELOG header                     = ${CHANGELOG_HEADER}
  Previous release tag (changelog)     = ${PREVIOUS_RELEASE_TAG}

Steps:
  1. Create ${CONSUL_RELEASE_BRANCH} from ${REMOTE}/${CONSUL_SOURCE_BRANCH} (and push if new)
  2. Create ${PREPARE_BRANCH} from ${CONSUL_RELEASE_BRANCH}
  3. Bump version/VERSION + CHANGELOG, then commit
  4. Push ${PREPARE_BRANCH} and open a PR into ${CONSUL_RELEASE_BRANCH}

EOF

if [[ "${DRY_RUN}" == "true" ]]; then
  echo ">>> DRY RUN: nothing will be created, changed, pushed, or opened."
  echo ">>> The commands that would run are printed below, prefixed with [dry-run]."
  echo ">>> Branch-existence checks use your local clone; run 'git fetch ${REMOTE}' first for accuracy."
  echo
elif [[ "${INTERACTIVE}" == "true" ]]; then
  read -r -p "Proceed? [y/N] " response || true
  case "${response}" in
    [yY] | [yY][eE][sS]) ;;
    *)
      echo "Aborted. No changes were made."
      exit 1
      ;;
  esac
fi

# -----------------------------------------------------------------------------
# 1. Create (or reuse) the point release branch from the long-lived source branch
# -----------------------------------------------------------------------------
echo "==> Fetching latest from ${REMOTE} (including tags)..."
run git fetch --tags "${REMOTE}"

if git show-ref --verify --quiet "refs/heads/${PREPARE_BRANCH}"; then
  fail_or_warn "local branch '${PREPARE_BRANCH}' already exists. Delete it or pick another version."
fi
if git rev-parse --verify --quiet "refs/remotes/${REMOTE}/${PREPARE_BRANCH}" >/dev/null; then
  fail_or_warn "branch '${PREPARE_BRANCH}' already exists on ${REMOTE}. Delete it or pick another version."
fi

if git rev-parse --verify --quiet "refs/remotes/${REMOTE}/${CONSUL_RELEASE_BRANCH}" >/dev/null; then
  echo "==> ${CONSUL_RELEASE_BRANCH} already exists on ${REMOTE}; using it as-is."
  run git checkout -B "${CONSUL_RELEASE_BRANCH}" "${REMOTE}/${CONSUL_RELEASE_BRANCH}"
else
  if ! git rev-parse --verify --quiet "refs/remotes/${REMOTE}/${CONSUL_SOURCE_BRANCH}" >/dev/null; then
    fail_or_warn "source branch '${CONSUL_SOURCE_BRANCH}' not found on ${REMOTE}. Set CONSUL_SOURCE_BRANCH to the long-lived branch to cut from."
  fi
  echo "==> Creating ${CONSUL_RELEASE_BRANCH} from ${REMOTE}/${CONSUL_SOURCE_BRANCH}..."
  run git checkout -b "${CONSUL_RELEASE_BRANCH}" "${REMOTE}/${CONSUL_SOURCE_BRANCH}"
  run git push -u "${REMOTE}" "${CONSUL_RELEASE_BRANCH}"
fi

# -----------------------------------------------------------------------------
# 2. Create the prepare branch from the point release branch
# -----------------------------------------------------------------------------
echo "==> Creating ${PREPARE_BRANCH} from ${CONSUL_RELEASE_BRANCH}..."
run git checkout -b "${PREPARE_BRANCH}"

# -----------------------------------------------------------------------------
# 3. Prepare the release: bump version/VERSION and prepend the CHANGELOG entry
# -----------------------------------------------------------------------------
echo "==> Bumping version/VERSION to ${CONSUL_RELEASE_VERSION}..."
echo "==> Generating CHANGELOG entry since ${PREVIOUS_RELEASE_TAG} (hashicorp/go-changelog)..."
if [[ "${DRY_RUN}" == "true" ]]; then
  printf '  [dry-run] write %q to version/VERSION\n' "${CONSUL_RELEASE_VERSION}"
  printf '  [dry-run] $ go run github.com/hashicorp/go-changelog/cmd/changelog-build@latest -last-release %q -entries-dir .changelog/ ...\n' "${PREVIOUS_RELEASE_TAG}"
  printf "  [dry-run] prepend '%s' + the changelog body to CHANGELOG.md\n" "${CHANGELOG_HEADER}"
else
  # Bump the embedded version (version/version.go reads this file via go:embed).
  printf '%s\n' "${CONSUL_RELEASE_VERSION}" >version/VERSION

  # changelog-build emits the changelog body (SECURITY/IMPROVEMENTS/... sections)
  # to stdout, reading the per-PR entries under .changelog/.
  changelog_body="$(go run github.com/hashicorp/go-changelog/cmd/changelog-build@latest \
    -last-release "${PREVIOUS_RELEASE_TAG}" \
    -entries-dir .changelog/ \
    -changelog-template .changelog/changelog.tmpl \
    -note-template .changelog/note.tmpl \
    -this-release "$(git rev-parse HEAD)")"
  # Drop the leading blank line(s) emitted by the changelog template.
  changelog_body="$(printf '%s\n' "${changelog_body}" | awk 'NF{f=1} f')"

  if [[ -z "${changelog_body}" ]]; then
    echo "Error: changelog-build produced no entries between ${PREVIOUS_RELEASE_TAG} and HEAD." >&2
    exit 1
  fi

  echo "==> Prepending '${CHANGELOG_HEADER}' to CHANGELOG.md..."
  {
    printf '%s\n' "${CHANGELOG_HEADER}"
    printf '%s\n\n' "${changelog_body}"
    cat CHANGELOG.md
  } >CHANGELOG.md.new
  mv CHANGELOG.md.new CHANGELOG.md
fi

if [[ "${DRY_RUN}" != "true" && -z "$(git status --porcelain)" ]]; then
  echo "Error: release preparation produced no changes; nothing to commit." >&2
  exit 1
fi

run git add -A
run git commit -m "changelog and version update ${CONSUL_RELEASE_VERSION}"

# -----------------------------------------------------------------------------
# 4. Push the prepare branch and open the PR
# -----------------------------------------------------------------------------
echo "==> Pushing ${PREPARE_BRANCH} to ${REMOTE}..."
run git push -u "${REMOTE}" "${PREPARE_BRANCH}"

PR_TITLE="Prepare release ${CONSUL_RELEASE_VERSION}"
PR_BODY="$(cat <<EOF
Automated release preparation for consul ${CONSUL_RELEASE_VERSION}.

Generated by \`release-scripts/prepare-release-branch.sh\`:
- Bumped \`version/VERSION\` to ${CONSUL_RELEASE_VERSION}.
- Prepended the \`${CHANGELOG_HEADER}\` CHANGELOG entry (hashicorp/go-changelog, since ${PREVIOUS_RELEASE_TAG}).

Base branch \`${CONSUL_RELEASE_BRANCH}\` was cut from \`${CONSUL_SOURCE_BRANCH}\`.
EOF
)"

echo "==> Opening pull request: ${PREPARE_BRANCH} -> ${CONSUL_RELEASE_BRANCH}..."
if [[ "${DRY_RUN}" == "true" ]]; then
  printf '  [dry-run] $ gh pr create --base %q --head %q --title %q --body <PR body>\n' \
    "${CONSUL_RELEASE_BRANCH}" "${PREPARE_BRANCH}" "${PR_TITLE}"
  echo
  echo "Dry run complete. No branches were created and nothing was pushed."
  exit 0
fi

PR_URL="$(gh pr create \
  --base "${CONSUL_RELEASE_BRANCH}" \
  --head "${PREPARE_BRANCH}" \
  --title "${PR_TITLE}" \
  --body "${PR_BODY}")"

echo
echo "Pull request created:"
echo "${PR_URL}"
